"""
MKT Original Commentary — Ezekiel chapters 21–22
Run: python3 scripts/zc-original-ezekiel-21-22-fill.py

Source data used:
- data/interlinear/ezekiel.json
- data/translation/glossary-hebrew.json (cherev, kavod, sigim, etc.)
- BDB and HALOT for key terms

Key decisions in this range:
- 21:27 triple 'avvah' rendered as three-fold overturning (triple emphasis)
- 21:27 'until he comes to whom the judgment belongs' — direct echo of Gen 49:10 noted
- 22:30 'man standing in the breach' — the failed intercessor whose role Christ fulfills
- cherev (sword) throughout ch21 tracked as divine judgment agent
- sigim/kur (dross/furnace) in ch22 as covenant-curse imagery from Lev 26
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZEKIEL_ORIGINAL = {
"21": {
    "1": '<p>Standard oracle-reception formula. Chapter 21 opens a sustained sword-oracle that constitutes Ezekiel\'s most concentrated meditation on the divine instrument of judgment. The Hebrew chapter division places the pivot differently: MT 21:1 = English 20:45, making the \'south/forest\' oracle the opening of this sword sequence. The English chapter numeration follows the LXX.</p>',
    "2": '<p><strong>sim panecha derekh teman</strong> (\'set your face toward the south\'): <em>sim panim</em> (set the face) is Ezekiel\'s characteristic direction-formula for prophetic address — the prophet physically orients toward the target of the oracle. The \'forest\' of the Negev is a figurative description, likely of Judah, since the Negev is not forested. The oracle establishes the direction before the target is named.</p>',
    "3": '<p><strong>ya\'ar haNegev</strong> (\'forest of the south/Negev\'): the allegory thin — the south-forest is Jerusalem-Judah. Fire devoured (<em>achel</em>) in the forest prepares for the explicit announcement that follows: \'I am about to draw my sword\' (v. 4). Every tree — righteous and wicked — is consumed, establishing the totalistic nature of the coming judgment.</p>',
    "4": '<p><strong>tzaddiq veresha</strong> (\'righteous and wicked\'): the sword indiscriminately cuts off both — a theological difficulty the exiles press (18:1-4; 33:10-20). YHWH\'s answer throughout chapters 18 and 33 is individual accountability, but here the sword oracle emphasizes the totalistic corporate judgment on the land as a whole. Both registers must be held: corporate judgment and individual accountability operate at different levels.</p>',
    "5": '<p><strong>kol-basar yeda ki-ani YHWH heretzti et-charvi mita\'rea</strong> (\'all flesh will know that I, YHWH, have drawn my sword from its sheath\'): the universal-recognition formula (<em>yeda\'</em>, they will know) applied to the sword-drawing. The sword in the sheath is a standard ancient Near Eastern idiom for restrained military power; drawing the sword means the restraint is now removed. YHWH himself is the one who draws — not merely permitting Babylonian aggression but actively initiating it.</p>',
    "6": '<p><strong>ne\'aneq beshivron motnayim</strong> (\'sigh with the breaking/shattering of the loins\'): the root <em>n\'q</em> (to sigh, groan, moan) combined with <em>shivron motnayim</em> (collapsing/breaking of loins — the body\'s core giving way). Ezekiel is commanded to perform grief so physically intense that it signals structural collapse — not mere sadness but bodily breakdown. The sign-act makes the prophet\'s body the first casualty of the announced judgment.</p>',
    "7": '<p><strong>lema ah atah ne\'aneq</strong> (\'why are you sighing?\'): the audience query that triggers the public explanation — the sign-act requires interrogation to become proclamation. The answer frames the coming catastrophe as something that will make \'every heart melt, all hands hang limp, every spirit faint, every knee turn to water\' — the full physiological register of paralytic terror (cf. 7:17).</p>',
    "8": '<p>Transition to the formal sword poem/oracle. The second oracle within the chapter sequence marks an escalation: from sign-act (sighing) to direct poetic speech about the sword. The sword oracle in vv. 8-17 is recognized as among the most intense martial poetry in the Hebrew Bible.</p>',
    "9": '<p><strong>cherev cherev huchaddah vegam meruqah</strong> (\'a sword, a sword — sharpened and polished\'): the doubled <em>cherev</em> intensifies urgency (cf. Jer 4:10 and other doubled words of alarm). <em>Huchaddah</em> (sharpened, Hophal of <em>chadd</em>) and <em>meruqah</em> (polished, Pual of <em>maraq</em>): the sword is combat-ready — the double preparation suggests both effectiveness (sharpened) and terror (gleaming). The war-readiness of the divine instrument is total.</p>',
    "10": '<p><strong>lematbeach tivchah</strong> (\'sharpened to make a slaughter\'): the sword\'s purpose is stated baldly — slaughter (<em>tevach</em>). The second half of the verse is notoriously difficult: <em>o nasis shevet beni</em> — \'or shall we rejoice/dismiss the rod of my son?\' may be a shocked question rejecting comfort-seeking when the scepter of Israel has itself become the target. The <em>shevet</em> (rod/scepter) that should represent Davidic authority is now itself being swept away.</p>',
    "11": '<p><strong>vetitten ota limrut lamatbeach lachuf</strong> (\'it is given to be polished, to be handled, to make a slaughter\'): three infinitives of purpose — the sword exists to be polished, handled, and used for slaughter. The passive \'it is given\' (nittenah) signals divine agency without explicitly naming YHWH as the giver. The sword has been commissioned and prepared; all that remains is its deployment.</p>',
    "12": '<p><strong>za\'aq vehaveil</strong> (\'cry out and wail\'): direct commands to Ezekiel to perform lamentation. <strong>hak-yerekha</strong> (\'strike your thigh\'): a gesture of distress — literally striking the upper thigh as a sign of horror and grief. Compare Jer 31:19 where the same gesture marks repentance. <em>Ki-hi haytah vichal-nesi\'ei Yisrael</em> (\'for it will be against all the princes of Israel\') — the royal class is named as the sword\'s target.</p>',
    "13": '<p><strong>bachan</strong> (\'test/proof\'): a brief, cryptic verse — \'it is tested\' or \'because it is a test.\' The verb <em>bachan</em> (to test, examine, prove) suggests the sword-judgment is also a divine probation — YHWH\'s action will prove the truth of his word and the nature of Israel\'s condition. <em>Vema tihyeh im-gam mateh bozit</em> (\'what then if even the despising rod will be no more?\') — the scepter of authority has been judged useless.</p>',
    "14": '<p><strong>hak-yad el-yad</strong> (\'clap hand to hand\'): Ezekiel is commanded to clap hands together — a sign of either grief or bitter irony (cf. 6:11; 22:13). <em>Cherev shalishit</em> (\'the sword doubled/tripled\'): the sword is to strike again and again — doubled, then tripled — against the slain. The intensification through repetition drives home the completeness of the judgment.</p>',
    "15": '<p><strong>lema\'an lamug lev</strong> (\'in order that hearts may melt\'): the sword\'s psychological as well as physical purpose — not merely killing but creating the paralytic terror in all who witness. Every gate is targeted (<em>achad sha\'ar mamgurut cherev\'\'am</em> — the sword positioned at every gate), ensuring there is no exit. The sword threatens from every direction.</p>',
    "16": '<p><strong>hitchaddi yemini hasmili le\'anaph panayich</strong> (\'be sharp, go right; direct yourself, go left — wherever your face is directed\'): the command to the sword to be versatile, omnidirectional. The sword\'s freedom of movement in any direction mirrors the chariot\'s omnidirectional movement from chapter 1 — both are divine instruments of perfect responsiveness to the divine will.</p>',
    "17": '<p><strong>vegam ani acha el-kappi</strong> (\'and I also will clap my hands\'): YHWH himself joins the clapping — the divine gesture that Ezekiel performed (v.14) is now performed by YHWH. <strong>vahinnichoti chemati</strong> (\'and I will satisfy/rest my fury\'): <em>nuach</em> (Hiphil, \'to cause to rest\') — the fury that has been building is brought to completion. The word <em>nuach</em> is also the word for \'Noah\' (Noach), though the pun is not in view here. The fury rests when it is fully enacted.</p>',
    "18": '<p>New oracle: <strong>sim lecha shetei derakhim</strong> (\'set for yourself two ways/roads\'): the road-sign oracle. Ezekiel is to draw a map showing two roads from Babylon — one to Jerusalem, one to Rabbah of Ammon. The dual-target establishes that Babylon\'s judgment is not specific to Judah but applies to the whole region. The \'sword of the king of Babylon\' serves YHWH\'s purposes in both directions.</p>',
    "19": '<p><strong>veber\'i bara\'</strong> (\'and engrave an engraving\'): the carved road-marker at the crossroads points both ways. <em>Rosh derekh ir</em> (\'the head of the road to a city\') — the fork in the road. The military intelligence Babylon actually used (divination at crossroads) is described here from the perspective of YHWH\'s sovereign direction of Babylonian decision-making: their divination will happen to point toward Jerusalem because YHWH has determined that outcome.</p>',
    "20": '<p><strong>lesim qesem qesem cherev el-Yerushalayim velo el-Rabbah Bnei-Ammon</strong> (\'to set divination — the sword against Jerusalem, and against Rabbah of Ammon\'): two targets of the same Babylonian sword. The oracle holds both in view simultaneously — Israel is not specially targeted; rather, the sword reaches all who stand under divine judgment. Ammon will receive its oracle in 21:28-32.</p>',
    "21": '<p><strong>ki-amad melech Bavel el-em haderekh bereshit shetei hadderakhim liqsom qasem</strong> (\'for the king of Babylon stands at the fork of the two roads, at the head of the two ways, to use divination\'): <em>qesem qesamim</em> (divination/divination) — an intensive or generalized form. Three divination methods listed: <em>herak bacheitzim</em> (shaking arrows/belomancy), consulting teraphim (<em>shal baterafim</em>), and examining a liver (<em>ra\'ah bakabed</em>). All three are condemned in Deuteronomy, yet here YHWH uses even Babylonian divination to accomplish his purpose.</p>',
    "22": '<p><strong>beyad-yemino hayah haqesem Yerushalayim</strong> (\'in his right hand was the divination — Jerusalem\'): the lot falls on Jerusalem. Whatever the Babylonian diviner intended, the outcome was divinely predetermined. <em>Latum krim</em> (to direct battering rams), <em>lif\'toch peh beretach</em> (to open the mouth in slaughter/with a shout), <em>leharim qol biteruah</em> (to raise the voice with a battle cry) — the military operations described in technical detail: siege equipment, shouting, and war-cry.</p>',
    "23": '<p><strong>uhem kiqsam shav be\'eineihem</strong> (\'and it will be to them like a false/empty divination in their eyes\'): the inhabitants of Jerusalem will dismiss the Babylonian divination as meaningless — their false prophets have told them they are safe. The sworn oaths (<em>shevuot shavu\'ot</em>) with which they have been reassured will create a false confidence that makes the judgment more devastating when it falls. The same dynamic recurs in 13:10: \'peace when there is no peace.\'</p>',
    "24": '<p><strong>laken koh amar Adonai YHWH ya\'an hizkarekhem avonekhem</strong> (\'therefore, because you have caused your iniquity to be remembered\'): the Babylonian divination that Jerusalem dismisses as empty is precisely the means by which YHWH \'remembers\' Israel\'s iniquity — that is, brings it into the sphere of active judgment. <em>Avon</em> (iniquity) remembered by YHWH is iniquity being brought to account.</p>',
    "25": '<p><strong>ve\'atah chalal rasha nesi Yisrael</strong> (\'and you, O profaned wicked prince of Israel\'): direct address to Zedekiah (or the Davidic monarchy generally). <em>Chalal</em> (profaned/pierced) — the prince has been desacralized, stripped of the protective holiness of the anointed office. <em>Asher-ba yomo be\'et avon qetz</em> (\'whose day has come, at the time when iniquity reaches its end\') — the convergence of the prince\'s failure and the end of the age of iniquity.</p>',
    "26": '<p><strong>haser hamitznefet veharim haketer</strong> (\'remove the turban and lift off the crown\'): two objects removed. <em>Mitznefet</em> (turban) is the high priestly turban (Ex 28:4; 39:28) — here worn by the prince, blurring royal and priestly roles. <em>Keter</em> (crown) is the royal diadem. The removal of both signals the simultaneous dissolution of both offices. <em>Zot lo-zot</em> (\'this shall not be this\'): the divine declaration that the present order of things is reversed — the high brought low and the low raised.</p>',
    "27": '<p><strong>avvah avvah avvah asimennah</strong> (\'overturned, overturned, overturned — I will make it\'): the triple repetition of <em>avvah</em> (ruin/overturning) is unparalleled in Hebrew prose — three successive destructions of the Davidic throne (Jehoahaz, Jehoiakim, Zedekiah — each deported or killed). <strong>gam-zot lo haytah</strong> (\'also this shall not be\') — the throne ceases. Then: <strong>ad-bo asher-lo hamishpat venatattihu</strong> (\'until he comes to whom the right/judgment belongs, and to him I will give it\'): the suspension formula — the throne is overturned and held in eschatological suspension until the one to whom it belongs by right arrives. This echoes Genesis 49:10 (<em>ad ki-yavo Shiloh</em>) — the scepter withheld until the one to whom it belongs claims it.</p>',
    "28": '<p><strong>uven-adam hinave el-Bnei Ammon</strong> (\'and son of man, prophesy to the Ammonites\'): the sword that was directed toward Jerusalem now pivots to Ammon. The oracle shows that YHWH\'s judgment is not partialistic: all nations under divine indictment receive the sword. Ammon mocked Israel\'s downfall (25:3-7); their turn is coming. The Ammonite oracle is brief compared to the Jerusalem oracle — the sustained focus on Israel reflects the depth of the covenant relationship.</p>',
    "29": '<p><strong>cherev cherev petuyah latatbeach meruqah</strong> (\'a sword, a sword unsheathed for slaughter, polished\'): the sword poem that opened in v.9 is reprised for Ammon — the same sharpened, polished sword turns toward Ammon. <em>Chazot shav</em> (\'while they see false visions\') — the Ammonite prophets who offered false comfort will be proved wrong as surely as Israel\'s false prophets were proved wrong. The sword does not spare those whose prophets promised peace.</p>',
    "30": '<p><strong>hashev el-ta\'areh</strong> (\'return it to its sheath\'): a shift — the command to return the sword to its sheath. This is not the end of judgment but a temporary withdrawal from the Ammonite oracle, anticipating the fuller judgment oracle against Ammon in chapter 25. <em>Bimqom asher nivrate sham tishafet</em> (\'in the place where you were created, there you will be judged\') — the land of origin is also the land of judgment.</p>',
    "31": '<p><strong>shafachti alecha za\'mi</strong> (\'I will pour out my indignation upon you\'): <em>za\'am</em> (indignation, burning anger) — a term used for YHWH\'s most intense categorical anger. <em>Nishaft\'ti alecha be\'esh evrati</em> (\'I will blow on you with the fire of my wrath\') — the breath/blowing of divine wrath as fire. The same terms used for judgment on Jerusalem (7:8; 22:22) are applied to Ammon.</p>',
    "32": '<p><strong>uchol-Yerushalayim umikol-ha\'aretz</strong> (\'to all Jerusalem and all the land\'): the Ammonite oracle ends with the declaration that Ammon will be \'fuel for the fire\' — burned as fuel rather than smelted as metal (the distinction between destruction and refining). <em>Lo tizakher ki ani YHWH dibarti</em> (\'you will not be remembered, for I, YHWH, have spoken\'): the finality formula — Ammon will be forgotten, not preserved as a witness. The covenant nation Israel receives judgment but is preserved through it; Ammon receives judgment and is obliterated. The distinction between covenant and non-covenant judgment is stark.</p>'
},
"22": {
    "1": '<p>Another oracle-reception formula opening a distinct unit. Chapter 22 is a sustained judicial proceeding — YHWH as prosecuting attorney presenting the case against Jerusalem in legal form (<em>hatishpot</em>, \'will you judge?\' — the interrogative implies Ezekiel is being commissioned as a judge). The catalogue of specific offenses (vv. 6-12) is the most comprehensive indictment list in Ezekiel.</p>',
    "2": '<p><strong>ha\'ir haddamim</strong> (\'the city of blood\'): a compound construct — Jerusalem named by its defining characteristic. <em>Damim</em> (bloods, plural) suggests multiple acts of bloodshed, accumulated guilt. The city\'s identity is fixed by what it has done with blood — the violation of Genesis 9:6 and Leviticus 17:11 (\'the blood is the life\') on a systemic scale. <em>Hoda\'at et kol-to\'evoteiha</em> (\'make known all her abominations\'): the prophet as prosecutorial witness.</p>',
    "3": '<p><strong>ir shofechet dam betocha</strong> (\'a city that sheds blood within herself\'): the blood is internal — Jerusalem\'s bloodguilt is not from external violence against foreigners but from internal exploitation and injustice. <em>Labo ittah</em> (\'to bring her time\'): the blood-shedding hastens YHWH\'s judgment — each act of injustice moves the eschatological clock. The idols made within the city add ritual defilement to moral bloodguilt.</p>',
    "4": '<p><strong>asha\'mt bedam asher shafacht</strong> (\'you have incurred guilt by the blood you shed\'): <em>asham</em> (guilt/guilt offering) — the legal term for offense requiring restitution/atonement. The verb form here places the guilt as already incurred, not merely potential. <em>Tameh biglulaich</em> (\'defiled by your idols\'): <em>tame\'</em> (ritually/morally unclean) — the same root used in Leviticus for the pollution that must be addressed through purification rituals, here applied to the systemic state of the city.</p>',
    "5": '<p><strong>qerovah vesheloha mimecha tiqalasena</strong> (\'those near and those far from you will mock you\'): the universal mockery that falls on the humiliated city. <em>Tamei hashem rabbat hamehumah</em> (\'defiled in name, abounding in turmoil\'): name-defilement — the city whose name should mean \'city of peace\' (Yerushalayim) is now defined by its defiled reputation. Turmoil (<em>mehumah</em>) as the defining atmosphere of the fallen city.</p>',
    "6": '<p><strong>hinneh nesi\'ei Yisrael ish lizro\'o hayu vach</strong> (\'the princes of Israel in you, each according to his arm/power, have shed blood\'): <em>ish lizro\'o</em> (\'each by his arm\') — each prince acting on his own strength/power, not under Torah constraint. The rulers are the first indicted in the catalogue. When leadership fails the covenant, every subsequent level of society follows. <em>Hayu vach lema\'an shefoch dam</em> (\'they were in you in order to shed blood\') — the purpose-clause makes the bloodshed deliberate, not incidental.</p>',
    "7": '<p><strong>av ve\'em haqelu vach</strong> (\'father and mother they have dishonored in you\'): the first specific offense — violation of the fifth commandment (Ex 20:12; Deut 5:16). The catalogue that follows closely mirrors the Holiness Code (Lev 17-26) and the Decalogue: parent-honor, treatment of strangers, orphans, and widows. <em>Lager asu ve\'oshek bethochech</em> (\'the resident alien they have oppressed\'): Leviticus 19:33-34 specifically commands fair treatment of the <em>ger</em> (resident alien).</p>',
    "8": '<p><strong>miqdashi bazit</strong> (\'my sanctuary you have despised\'): the verb <em>baz</em> (to despise, treat with contempt) — active disregard for the sacred. <em>Et-shabbatotai chillalt</em> (\'my sabbaths you have profaned\'): <em>challal</em> (profane/desecrate) — the sabbath as covenant sign (Ex 31:13-17) is violated by treating it as an ordinary day. The pairing of sanctuary-contempt and sabbath-profanation brackets the whole cultic system of covenant order.</p>',
    "9": '<p><strong>anshei rachil hayu vach lema\'an shefoch dam</strong> (\'slanderers were in you for the purpose of shedding blood\'): <em>rachil</em> (tale-bearer/slanderer) — from the root meaning to go about/peddle; the one who circulates damaging reports. The legal prohibition in Lev 19:16 explicitly connects slanderous tale-bearing with endangering lives. <em>Zimmah</em> (lewdness/shameful conduct) — a strong term for sexual and moral perversion.</p>',
    "10": '<p><strong>erva av gilla vach</strong> (\'the nakedness of a father they have uncovered in you\'): incest-language drawn directly from Leviticus 18 — \'uncovering nakedness\' as the standard euphemism for prohibited sexual relations. The specific listing of violations — father\'s wife, women in their impurity — follows the Levitical list almost verbatim, demonstrating that the indictment is based on specific Torah legislation already in force.</p>',
    "11": '<p><strong>ish et-eshet re\'ehu asah to\'evah</strong> (\'each man did abomination with his neighbor\'s wife\'): <em>to\'evah</em> (abomination) — the term used throughout Leviticus 18 for the sexual violations that \'defile the land\' (Lev 18:27). The list includes adultery, incest with daughter-in-law, and violation of a half-sister. The word <em>to\'evah</em> links these sexual offenses to the idolatry described earlier — both are categorized as covenant-defiling abominations.</p>',
    "12": '<p><strong>shochad lachu vach lema\'an shefoch dam</strong> (\'bribes they have taken in you for the purpose of shedding blood\'): the economic/judicial corruption — bribery corrupts the justice system, leading to wrongful deaths. <em>Neshech vetarbith laqachta</em> (\'interest and increase you have taken\'): <em>neshech</em> (biting interest, from <em>nashak</em>, to bite) and <em>tarbith</em> (increase/profit) — the two prohibited forms of usury from Leviticus 25:36-37. Both exploit the economically vulnerable and violate the covenant economic order. <em>Oti shachacht</em> (\'me you have forgotten\') — the summary of all the offenses: the root cause is forgetting YHWH.</p>',
    "13": '<p><strong>hinneh hikiti kapi el-bitzek\'ach asher asit</strong> (\'I have struck my hands together over your unjust gain\'): YHWH performs the hand-clapping gesture (cf. 21:14, 17) — here as a sign of judgmental finality, possibly mimicking a legal sealing-of-verdict action. The gesture marks the decisive moment when the divine judge has heard enough evidence and pronounces the verdict.</p>',
    "14": '<p><strong>hayya\'amod libech</strong> (\'will your heart endure?\'): the interrogative challenges the city\'s imagined resilience. <em>Im-techazaknah yadayich</em> (\'or will your hands be strong?\'): the rhetorical questions expect \'no\' — the heart that tolerated all the abominations will not endure when YHWH acts. <em>Bayamim asher ani oseh otach</em> (\'in the days when I deal with you\') — the divine dealing is certain; only the timing is unspecified.</p>',
    "15": '<p><strong>vehifitzotich bagoyim vezereticha ba\'aratsot</strong> (\'I will scatter you among the nations and disperse you among the lands\'): the covenant-curse of dispersion (Lev 26:33; Deut 28:64) explicitly enacted. <em>Vatimachti timatchich mimmech</em> (\'and I will consume your filth from you\'): the dispersion serves a purifying function — the removal of the impurity from the land, even through the harsh means of exile. The land vomits out its inhabitants (Lev 18:28).</p>',
    "16": '<p><strong>venicchalit bach le\'einei goyim</strong> (\'you will be profaned in yourself before the eyes of the nations\'): <em>challal</em> (profaned) — the city that profaned YHWH\'s sanctuary will itself be profaned before the watching nations. The public nature of the humiliation mirrors the public nature of the abominations: what was done visibly in the temple courtyards will be answered by visible public judgment. <em>Yada\'ta ki-ani YHWH</em>: recognition-formula closing the indictment section.</p>',
    "17": '<p>Transition to the furnace/smelting allegory (vv. 17-22). The oracle now shifts from a legal catalogue of offenses to a metallurgical metaphor for the purifying action of judgment. This unit is complete in itself: diagnosis (vv. 17-19), process (vv. 20-21), and result (v. 22).</p>',
    "18": '<p><strong>hayu-li beit Yisrael le-sigim</strong> (\'the house of Israel has become dross to me\'): <em>sigim</em> (dross, slag) — the worthless residue left after refining metal. All that Israel has become is listed: dross of silver, bronze, tin, iron, and lead. The precious metal (silver) has become slag; the base metals that contaminate it are now all that remains. The metallurgical vocabulary was familiar in the ancient Near East: Mesopotamian texts speak of gods refining their people as a smith refines silver.</p>',
    "19": '<p><strong>lachen koh amar Adonai YHWH ya\'an heyot kulchem le-sigim</strong> (\'because all of you have become dross\'): the <em>lachen</em> (therefore) marks the consequence that follows from the metallurgical diagnosis. The gathering of Israel into the furnace-city (<em>kur</em>) is explicitly compared to gathering metal for smelting: <em>qibbetz etchem el-toch Yerushalayim</em> (\'I will gather you into the midst of Jerusalem\').</p>',
    "20": '<p><strong>kiqibbutz kesef unchoshet uvarzel ve\'oferet ve\'bdil el-toch kur</strong> (\'as silver and copper and iron and lead and tin are gathered into a furnace\'): the complete list of smelted metals gathered for the furnace. <em>Lenafuach alav esh</em> (\'to blow fire upon it\'): the bellows of the smelter that intensifies the heat. YHWH is both the metallurgist who has diagnosed the dross and the one who works the bellows: <em>apen bi\'api ushilchti etchem</em> (\'I will blow with my wrath and I will put you in and melt you\').</p>',
    "21": '<p><strong>vekanavasti etchem vefachati aleichem be\'esh evrati venitu\'sem betochatah</strong> (\'I will gather you and blow upon you with the fire of my wrath, and you will be melted in its midst\'): the extended metaphor reaches its climax — YHWH as the divine smelter working the furnace with his own breath of wrath. <em>Evrati</em> (my wrath/overflow) — the same word as \'outburst\' — the uncontained energy that drives the smelting heat. The city is the furnace and the people are the metal to be melted.</p>',
    "22": '<p><strong>kehintoch kesef betoch kur ken tinatchu betochah</strong> (\'as silver is melted in the midst of a furnace, so you will be melted in its midst\'): the simile made explicit — the metaphor\'s equation stated plainly. <em>Veyeda\'tem ki-ani YHWH shafachti chamati aleichem</em> (\'and you will know that I, YHWH, have poured out my fury upon you\'): the recognition-formula closes the smelting oracle. The knowledge gained through the furnace-judgment is the goal of the whole process.</p>',
    "23": '<p>A new word-reception formula introduces the oracle against the land\'s classes (vv. 23-31). The land is diagnosed as <em>lo ge\'ushma beyom za\'am</em> (\'not rained upon in the day of indignation\') — a land that should have received the cleansing rain of YHWH\'s blessing has instead received only the drought of judgment. The social analysis that follows moves class by class through the failure of every sector of leadership.</p>',
    "24": '<p><strong>lo ge\'ushma beyom za\'am</strong> (\'not cleansed/rained upon in the day of wrath\'): <em>ge\'ushma</em> (a hapax legomenon, likely from <em>gasham</em>, to rain) — the land that has not received purifying rain is parched and unclean. The \'day of wrath\' (<em>yom za\'am</em>) echoes the \'day of YHWH\' language of chapter 7. The land\'s condition as unwatered/uncleansed is the environmental correlate of its moral condition.</p>',
    "25": '<p><strong>qesher nevi\'eiha bequirbah</strong> (\'a conspiracy of her prophets in her midst\'): the prophets are indicted first — as the primary source of false guidance. <em>Ke\'aryeh sho\'eg toreh taref</em> (\'like a roaring lion tearing the prey\'): the prophets who should protect and guide the flock have become predators. <em>Nefashot lachu</em> (\'they devour lives/souls\') — the false prophets consume the people they claim to serve. <em>Choshen nachalah lavku</em> (\'they have taken treasure and wealth\') — the prophets profit materially from their falsehoods.</p>',
    "26": '<p><strong>kohaneiha chamesu torati veyechalelu qodoshai</strong> (\'her priests have done violence to my Torah and profaned my holy things\'): <em>chamas</em> (violence/wrong) applied to Torah-treatment — the priests have violated the Torah they were commissioned to teach. <em>Bein qodesh lechol lo hivdilu</em> (\'between holy and common they have not distinguished\'): the priestly function is precisely the making of distinctions (Lev 10:10-11; Deut 33:10) — between holy and common, clean and unclean. The priests have blurred the very boundaries they exist to maintain. <em>Shabbetotai he\'elemu eineihem meyhem</em> (\'and from my Sabbaths they have hidden their eyes\').</p>',
    "27": '<p><strong>sareiha bequirbah ke\'ze\'evim torfei taref</strong> (\'her officials in her midst are like wolves tearing the prey\'): the officials/rulers are wolves — predators on the very community they govern. <em>Lishpoch dam le\'abed nefashot lema\'an beroa batza\'</em> (\'to shed blood, to destroy lives, for the sake of dishonest gain\'): the officials\' specific failure — they use their power not for justice but for extraction. The three classes — prophets (v25), priests (v26), and officials (v27) — are each indicted in order of expected covenant faithfulness.</p>',
    "28": '<p><strong>venevi\'eiha tachu lahem tafal</strong> (\'and her prophets have plastered over them with whitewash\'): the prophets\' second indictment — they cover up the officials\' crimes with false reassurance. <em>Tafal</em> (whitewash/plaster of no value) — cheap, cosmetic covering over structural defects. <em>Chazim shav velohesim lahem kazav</em> (\'seeing false visions and divining lies for them\'): the prophets serve the corrupt officials by providing theological cover — false visions that validate what the officials want to do. The same image as 13:10-16.</p>',
    "29": '<p><strong>am ha\'aretz asheq asheq vegazu gazel</strong> (\'the people of the land have practiced oppression and committed robbery\'): the final class — the common people themselves are indicted. <em>Ani ve\'evyon honu</em> (\'the poor and needy they have wronged\'): <em>hona</em> (to oppress/wrong, often economically) — the most vulnerable members of society exploited by those who should protect them. The covenant\'s particular concern for the poor (Ex 22:21-27; Lev 19:9-10; Deut 24:10-22) is comprehensively violated at every social level.</p>',
    "30": '<p><strong>avakesh me\'ahem ish godar geder ve\'omed baperetz lefanai</strong> (\'and I sought from them a man building a wall and standing in the breach before me\'): <em>godar geder</em> (one who builds a wall/fence) — the intercessor as structural restorer. <em>Ve\'omed baperetz</em> (\'standing in the breach\'): the military image of a defender standing in the gap made in a city wall during siege — the last defender who could prevent the collapse. Moses was the archetypal breach-stander (Ps 106:23). YHWH searched for one human being among all the prophets, priests, officials, and people — and found none. <em>Velo matza\'ti</em>: three words that carry the weight of Israel\'s total failure of intercessory representation.</p>',
    "31": '<p><strong>vashpoch aleichem za\'mi be\'esh evrati killitihem</strong> (\'I poured out my fury upon them; with the fire of my wrath I consumed them\'): the result of finding no intercessor — judgment proceeds without any mediating figure to stay it. <em>Derekham berosham natati</em> (\'their way I repaid on their own heads\'): the covenant principle of lex talionis elevated to the national level — what Israel has done returns to Israel as its own judgment. The final word of the chapter is <em>ne\'um Adonai YHWH</em> (\'declares the Lord YHWH\'), the sealing oracle-formula, affirming that the divine sentence is irrevocable.</p>'
}
}

def main():
    existing = load_comm('mkt-original', 'ezekiel')
    merge_comm(existing, EZEKIEL_ORIGINAL)
    save_comm('mkt-original', 'ezekiel', existing)
    print('Ezekiel 21-22 mkt-original commentary written.')

if __name__ == '__main__':
    main()
